"""
MKT Original Commentary — Psalms 90–95 (87 verses)
Run: python3 scripts/zc-original-psalms-90-95.py

Key decisions:
- Ps 90: Moses psalm; māʿôn (dwelling-place) as God's permanent location vs human
  transience; yālad applied to mountains (before they were born, v2); kĕmô-hegeh
  (like a sigh/groan, v9) as the years' end; limnôt yāmênû (counting days, v12) as
  the sapiential core; nōʿam (pleasantness/graciousness) as the closing petition
- Ps 91: shadday + ʿelyôn pair (vv1-2); wing-shelter (ʾebrāh, v4); qeṭeb-ṣohŏrāyim
  (noonday destruction, v6); vv11-12 quoted by Satan in Matt 4 (the text does not
  err — the adversary misapplies it); shaḥal (lion, v13) + ʿêpheh (cobra); divine
  first-person speech (vv14-16) as covenant pledge
- Ps 92: only Sabbath-titled psalm; rĕʾēm-horn (wild ox, v10); ṣaddîq-kĕtāmār
  (righteous like palm, v12); the Sabbath frame: creation's goodness celebrated even
  when the wicked seem to flourish
- Ps 93: YHWH-mālākh formula (v1) opens the enthronement psalm cluster (93, 95-99);
  three-fold nĕhārôt (floods) echoes the chaos-sea battle; ʿēdōtekhā (decrees, v5)
  as the moral parallel to creation order
- Ps 94: ʾēl-nĕqāmôt (God of retributions, v1) — nĕqāmāh as restorative justice not
  revenge; qal-wahomer argument (vv9-10: Creator knows what he made); hebel-verdict
  on human thoughts (v11, cited 1 Cor 3:20); mĕnûḥāh (rest, Ps 95:11) as the
  framework Heb 3-4 exegetes
- Ps 95: first of the enthronement psalms to shift to warning; hayyôm (today, v7)
  as the urgent threshold before hardening; ʾāqûṭ (I loathed, v10) uniquely intense
  verb for divine reaction to the wilderness generation; mĕnûḥāh (rest, v11) — Heb
  3:7-4:11 reads this as still-available eschatological rest
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW = {
  "90": {
    "1": "<p><b>tĕphillāh lĕmōsheh ʾîsh hāʾĕlōhîm</b> — <i>A Prayer of Moses, the man of God</i>. The attribution to Moses makes Psalm 90 unique — the only Mosaic psalm in the Psalter. <i>ʾÎsh hāʾĕlōhîm</i> (man of God) is the title for prophets who speak God's word (Deut 33:1; 1 Kgs 13:1; 2 Kgs 4:7). <b>ʾădōnāy māʿôn ʾattāh hāyîtā llānû bĕdōr wādōr</b> — <i>Lord, you have been our dwelling place in every generation</i>. <i>Māʿôn</i> (home, habitation, dwelling place — the permanent residence of God as Israel's refuge across all generations; cf. Deut 33:27: <i>mĕʿônāh ʾĕlōhê qedem</i>, the eternal God is your dwelling). The psalm anchors the fleeting human life (vv3-10) against the eternal divine habitation.</p>",
    "2": "<p><b>bĕṭerem hārîm yullādû</b> — <i>before the mountains were born</i>. <i>Yālad</i> (to bear, give birth) applied to the mountains — the creation of the mountains described as a birth event, personifying the earth's formation as parturition. <b>wattĕḥôlēl ʾereṣ wĕtēbēl</b> — <i>or you had formed the earth and the world</i>. <i>Ḥûl</i> (polel: to writhe in labor, bring forth in birth-pangs) — earth and inhabited world brought forth in a cosmic labor. <b>ûmēʿôlām ʿad-ʿôlām ʾattāh ʾēl</b> — <i>from age to age you are God</i>. The frame: creation events (mountains, earth) bracket the eternal divine being. God predates his own creation — the pre-creation God who will outlast it.</p>",
    "3": "<p><b>tāshēb ʾĕnôsh ʿad-dakkāʾ</b> — <i>you turn human beings back to dust</i>. <i>Dakkāʾ</i> (a crushed thing, powder, dust — from dākāʾ: to crush) — humanity returned to the crushed, pulverized state of pre-formation. The reversal of the creation-act of Gen 2:7 (<i>wayyîṣer YHWH ʾĕlōhîm ʾet-hāʾādām ʿāpār</i>: from dust taken, to dust returned, Gen 3:19). <b>wattōʾmer shûbû bĕnê-ʾādām</b> — <i>and you say, 'Return, O children of Adam!'</i> The divine word that reverses creation — <i>shûbû</i> (return) being the opposite of the forming act. <i>Bĕnê-ʾādām</i> (sons of Adam/humanity) — the collective solidarity of all human beings with the first human who was returned to dust.</p>",
    "4": "<p><b>kî ʾelep shānîm bĕʿênêkhā kĕyôm ʾetmôl kî yaʿăbōr</b> — <i>for a thousand years in your sight are like yesterday after it has passed</i>. The divine perspective on time: a thousand years (<i>ʾelep shānîm</i>) as yesterday in retrospect (<i>ʾetmôl kî yaʿăbōr</i>: yesterday after it has gone by — i.e., past and therefore experienced as short). <b>wĕʾashmûrāh balllāylāh</b> — <i>or like a single watch in the night</i>. <i>ʾAshm ûrāh</i> (a watch — the ancient division of the night into three or four watches, each 3-4 hours). A thousand years equals the briefest human unit of experienced time — not that time is unreal but that the divine relationship to it is utterly other (cf. 2 Pet 3:8's use of this verse).</p>",
    "5": "<p><b>zĕramtām shēnāh yihyû</b> — <i>you sweep them away like a flood; they are like a dream</i>. <i>Zāram</i> (to pour out in a torrent, sweep away — used of a rainstorm-flood; the sudden overwhelming inundation). <i>Shēnāh</i> (sleep) — human generations like a dream that dissolves on waking; no substance persisting after the divine gaze. <b>baqqōqer kĕḥāṣîr yaḥălōph</b> — <i>in the morning they are like grass that sprouts</i>. <i>ḥāṣîr</i> (grass, fresh vegetation — the type of rapid, ephemeral growth) that pushes up in the morning dew. The grass metaphor of Isa 40:6-8: all flesh is grass.</p>",
    "6": "<p><b>baqqōqer yāṣîṣ wĕḥālāph</b> — <i>in the morning it blossoms and shoots up</i>. <i>Yāṣîṣ</i> (to blossom, flourish — the brief flowering of the grass) + <i>ḥālap</i> (to pass on, to shoot up quickly). <b>lāʿereb yĕmôlēl wĕyābēsh</b> — <i>by evening it is mown down and withers</i>. <i>Mālal</i> (polal: to be cut off, mowed down) + <i>yābēsh</i> (to dry up, wither) — the complete life-cycle of grass compressed into a single day: morning blooming to evening withering. The same imagery in Isa 40:7-8 applied to nations; in Ps 90 applied to human generations.</p>",
    "7": "<p><b>kî-khālînû bĕʾappekhā</b> — <i>for we are brought to an end by your anger</i>. <i>Kālāh</i> (niphal: to be finished, brought to completion/end) — the divine anger as the agent that brings human existence to its terminus. <b>ûbăḥămātĕkhā nibbhālnû</b> — <i>by your fury we are overwhelmed/terrified</i>. <i>Bāhal</i> (niphal: to be dismayed, terrified, overwhelmed — the panic of sudden shock). The pairing of <i>ʾap</i> (anger, the flared nostril) and <i>ḥēmāh</i> (fury, hot wrath) — the two Hebrew terms for divine anger in increasing intensity.</p>",
    "8": "<p><b>shattāh ʿăwōnōtênû lĕnegdekhā</b> — <i>you have placed our sins before you</i>. <i>Shît lĕneged</i> (to set before, display in plain sight) — the divine perspective sees what is hidden to others: the sins are placed <i>lĕnegedekhā</i> (before your face, in your presence). <b>ʿălûmēnû lîʾôr pānêkhā</b> — <i>our hidden faults in the full light of your presence</i>. <i>ʿAlûm</i> (hidden thing, secret fault — from ʿālam: to conceal) — what is concealed from human sight is exposed in the divine light (<i>ʾôr pānêkhā</i>: the light of your face). The divine omniscience as the context for human mortality.</p>",
    "9": "<p><b>kî khol-yāmênû pānû bĕʿebrātekhā</b> — <i>all our days slip away under your wrath</i>. <i>Pānāh</i> (to turn away, to pass away — as a day turns and is gone). <b>killînû shānênû kĕmô-hegeh</b> — <i>we bring our years to an end like a sigh</i>. <i>Hegeh</i> (a sound, murmur, groan — from hāgāh: to murmur, meditate; the low sound of sighing, or possibly the growl of a lion, or the cooing of a dove — the onomatopoeic word for a brief, soft sound). Human years brought to an end with a murmur — not a shout but a barely audible exhalation. The restraint of the image makes mortality more, not less, poignant.</p>",
    "10": "<p><b>yĕmê-shĕnôtênû bāhem shĭbʿîm shānāh</b> — <i>the span of our years is seventy</i>. The first statement of a human lifespan as a defined quantity — <i>shĭbʿîm shānāh</i> (70 years) + <i>wĕʾim bigĕbûrōt shĕmônîm shānāh</i> (and if strong, 80 years). These are not averages but ideals — the maximum ordinarily achievable without special divine extension. <b>wĕrāhbām ʿāmāl wāʾāwen</b> — <i>but even then they contain only toil and grief</i>. <i>ʿĀmāl</i> (toil, trouble, grievous labor) + <i>ʾāwen</i> (trouble, iniquity, emptiness) — the substance of the extended years. <b>kî-gāz ḥîsh wannaʿûphāh</b> — <i>for they pass quickly and we fly away</i>. <i>Gāz</i> (to cut off, pass quickly — the rapid passing); <i>ʿûph</i> (to fly away — as a bird takes sudden flight).</p>",
    "11": "<p><b>mî-yôdēaʿ ʿōz ʾappekhā</b> — <i>who truly grasps the force of your anger?</i> The rhetorical question: who has really reckoned with the weight (<i>ʿōz</i>: strength, force) of the divine anger? <b>ûkĕyirʾātekhā ʿebrātekhā</b> — <i>who fears your wrath as it deserves?</i> <i>Ûkĕyirʾātekhā</i> (according to/equal to your being feared) — the fear the divine wrath is owed but not paid. The implication: no one fully grasps it, which makes the plea of v12 (wisdom to count our days) all the more necessary.</p>",
    "12": "<p><b>limnôt yāmênû kēn hôdaʿ</b> — <i>teach us to count our days aright</i>. <i>Limnôt</i> (to count, reckon, number) — not mere arithmetic but moral reckoning: to assign each day its true weight knowing its finitude. <i>Hôdaʿ</i> (hiphil imperative of yādaʿ: teach, make known) — the wisdom-petition addressed to YHWH. <b>wĕnābîʾ lĕbab ḥokhĕmāh</b> — <i>that we may acquire a wise heart</i>. <i>Lĕbab ḥokhĕmāh</i> (a heart of wisdom) — wisdom located in the heart (the seat of understanding and decision), arrived at by the discipline of mortality-awareness. The psalm's intellectual core: the proper response to human finitude is not despair but wisdom.</p>",
    "13": "<p><b>shûbāh YHWH ʿad-māthāy</b> — <i>turn back, LORD! How long will this go on?</i> The communal lament imperative — <i>shûb</i> (return, relent — the opposite of divine turning-away) + <i>ʿad-māthāy</i> (how long? — the standard lament formula). <b>wĕhinnāḥēm ʿal-ʿăbādêkhā</b> — <i>have mercy on your servants!</i> <i>Nāḥam</i> (niphal: to relent, be moved to compassion — the divine turning from judgment to mercy). The pivot from the meditation on mortality to petition: having stared into the reality of human finitude (vv3-11) and sought wisdom (v12), now the community cries out for divine relenting.</p>",
    "14": "<p><b>śabĕʿênû babbōqer ḥasdekā</b> — <i>fill us in the morning with your steadfast love</i>. <i>Śābaʿ</i> (hiphil: to satisfy, fill — the same word used of Ps 88:3 where the soul was filled with troubles; now the petition is to be filled instead with <i>ḥesed</i>). The morning as the time of grace: just as the grass springs up in the morning (v6), let the divine steadfast love spring up first. <b>ûnĕrannĕnāh wĕnishmaḥāh bĕkhol-yāmênû</b> — <i>so that we may celebrate and rejoice through all our days</i>. The goal: that the <i>ḥesed</i> filling the morning will sustain joy through the entire brief human lifespan.</p>",
    "15": "<p><b>śammĕḥênû kiymôt ʿinnîtānû</b> — <i>give us gladness to match the days you have made us suffer</i>. The petition for proportional gladness — joy equal in measure to the suffering: <i>kiymôt</i> (like the days of) the affliction (<i>ʿinnîtānû</i>: you humbled/afflicted us). <b>shĕnôt rāʾînû rāʿāh</b> — <i>joy equal to the years we have known trouble</i>. The request is not for suffering to be denied but for it to be matched and ultimately overcome by gladness — a balance-of-years theology that assumes God can and will compensate.</p>",
    "16": "<p><b>yērāʾeh ʾel-ʿăbādêkhā phāʿŏlekā</b> — <i>let your work appear to your servants</i>. <i>Phōʿal</i> (work, deed — the divine action in history) — the petition that the divine work become visible again to those who serve God. <b>wahădarĕkhā ʿal-bĕnêhem</b> — <i>and your splendor shine on their children</i>. <i>Hādār</i> (splendor, majesty, honor) — the divine glory that was seen in the Exodus and the wilderness now sought for the next generation (<i>bĕnêhem</i>: their children). The generational hope: the parents who suffered will not see the full manifestation, but their children will.</p>",
    "17": "<p><b>wîhî nōʿam ʾădōnāy ʾĕlōhênû ʿālênû</b> — <i>may the favor of the LORD our God rest upon us</i>. <i>Nōʿam</i> (pleasantness, grace, beauty, favor — from nāʿēm: to be pleasant, beautiful; cf. Naomi's name). The closing petition: the divine pleasantness resting on the community as its permanent atmosphere. <b>ûmaʿăśēh yādênû kônĕnāh ʿālênû</b> — <i>establish the work of our hands</i>. <i>Kôn</i> (hiphil: to establish firmly, make permanent) — the double petition with the doubly stated refrain: the human work (<i>maʿăśēh yādênû</i>) given permanence by divine action. The psalm closes where it opened: the permanent God asked to give permanence to what human hands create in their brief span.</p>"
  },
  "91": {
    "1": "<p><b>yōshēb bĕsēter ʿelyôn bĕṣēl shadday yitlônān</b> — <i>whoever lives in the shelter of the Most High will rest in the shadow of the Almighty</i>. <i>Sēter</i> (shelter, hiding place, secret place — from sātar: to hide) + <i>ʿelyôn</i> (Most High — the Canaanite epithet for the supreme deity, adopted as a title for YHWH). <i>Bĕṣēl</i> (in the shadow — the cool shade cast by a protecting presence) + <i>shadday</i> (the Almighty — the patriarchal name of God, especially prominent in Genesis and Job). The two divine titles (<i>ʿelyôn</i> and <i>shadday</i>) together invoke the God who is both supremely exalted and near enough to cast a sheltering shadow.</p>",
    "2": "<p><b>ʾōmar laYHWH maḥsî ûmĕṣûdātî ʾĕlōhay ʾebaṭaḥ-bô</b> — <i>I will say to the LORD, 'You are my refuge and my fortress, my God, in whom I trust.'</i> <i>Maḥseh</i> (refuge — the place of shelter in storm or danger) + <i>mĕṣûdāh</i> (fortress, stronghold — the military fortification; from ṣûd: to hunt, to surround). The personal profession: <i>ʾĕlōhay</i> (my God) + <i>ʾebaṭaḥ-bô</i> (I trust in him) — the shift from third-person description (v1) to first-person confession, making the general promise personal.</p>",
    "3": "<p><b>kî hûʾ yaṣṣîlĕkhā mippah yāqûsh</b> — <i>he will rescue you from the hunter's trap</i>. <i>Naṣal</i> (hiphil: to rescue, deliver — the Exodus deliverance verb) from the <i>pah yāqûsh</i> (fowler's snare — the trap laid for birds). The snare metaphor: the enemies and their plans as a fowler's trap into which the trusting person might fall but from which YHWH delivers. <b>middeber hawwôt</b> — <i>and from every deadly disease</i>. <i>Deber</i> (pestilence, plague — one of the Exodus plagues, here personified as a threat from which YHWH rescues).</p>",
    "4": "<p><b>bĕʾebrātô yāsekh lākh wĕtaḥat kĕnāphāyw teḥseh</b> — <i>he will shelter you under his feathers; you will find refuge beneath his wings</i>. <i>ʾEbrāh</i> (feathers, pinions — the large flight feathers of a bird's wing) + <i>kĕnāphāyw</i> (his wings) — the dual metaphor of the mother bird protecting her young (cf. Deut 32:11's eagle metaphor; Ps 17:8; 36:7; Ruth 2:12). <b>ṣinnāh wĕsōḥērāh ʾĕmûnātô</b> — <i>his faithfulness is your shield and armor</i>. <i>Ṣinnāh</i> (large shield — the full body-shield) + <i>sōḥērāh</i> (encircling protection, buckler — a round shield or the protective encirclement itself). Divine faithfulness (<i>ʾĕmûnāh</i>) as body-armor — the reliability of God's character as the believer's defense.</p>",
    "5": "<p><b>lōʾ tîrāʾ mippahad lāylāh</b> — <i>you will not fear the terror that comes in the night</i>. <i>Pahad</i> (dread, terror — the sudden overwhelming fear) that comes <i>lāylāh</i> (in the night — the time of darkness and vulnerability). <b>mēḥēṣ yāʿûph yômām</b> — <i>nor the arrow that flies in the daylight</i>. The four threats in vv5-6 span the dimensions of danger: night-terror, daylight-arrow (visible enemy), dark-pestilence, noon-destruction — every time and every kind of threat.</p>",
    "6": "<p><b>middeber bāʾōphel yahălōkh</b> — <i>nor the disease that moves through the dark</i>. <i>Deber</i> (pestilence) that <i>yahălōkh bāʾōphel</i> (walks in darkness — the darkness of night). <b>miqqeṭeb yāshûd ṣohŏrāyim</b> — <i>or the plague that strikes at noon</i>. <i>Qeṭeb</i> (destruction, a destroying power — used in Deut 32:24 of pestilence; Isa 28:2 of storm-devastation) + <i>ṣohŏrāyim</i> (noon, midday — the blazing heat of noon). The <i>qeṭeb ṣohŏrāyim</i> became in the Septuagint the <i>daimonion mesembrinon</i> (the noonday demon) — the medieval spiritual tradition's identification of acedia (spiritual torpor) with this noon-striking plague.</p>",
    "7": "<p><b>yippōl mişşidĕkhā ʾelep ûrĕbābāh mîmînekhā</b> — <i>a thousand may fall beside you, ten thousand at your right hand</i>. The military imagery: battlefield casualties surrounding the protected one. <i>ʾElep</i> (thousand) + <i>rĕbābāh</i> (ten thousand — the highest number word in Hebrew; cf. the song of 1 Sam 18:7). <b>ʾēlekhā lōʾ yiggāsh</b> — <i>but it will not reach you</i>. <i>Nāgaʿ</i> (to touch, reach, strike) — the destruction that strikes ten thousand will not make contact with the protected one. Not a claim of physical invincibility but of covenant protection amid universal mortality.</p>",
    "8": "<p><b>raq bĕʿênêkhā tabbîṭ</b> — <i>you will only watch with your own eyes</i>. <i>Raq</i> (only, merely) — the sole action: watching with open eyes. <b>wĕshillumāt rĕshāʿîm tirʾeh</b> — <i>and see the fate of the wicked</i>. <i>Shillumāh</i> (retribution, recompense — from shālem: the paying back what is owed) of the wicked — the trusting person is a spectator to the judgment that falls on those who do not trust. The position is not active participation in the judgment but witness to it.</p>",
    "9": "<p><b>kî-ʾattāh YHWH maḥsî</b> — <i>because you have made the LORD your refuge</i>. The <i>kî</i> (because) gives the reason for the protection of vv5-8: the ground is the decision made — YHWH chosen as refuge (<i>maḥseh</i>: the hiding place). <b>ʿelyôn śamtā mĕʿônekhā</b> — <i>the Most High your dwelling place</i>. <i>Māʿôn</i> — the same word as Ps 90:1 (God as the dwelling place) — here the human makes the divine dwelling place their own habitation. The symmetry: God is humanity's dwelling (Ps 90:1), and the Most High is the trusting person's dwelling (91:9).</p>",
    "10": "<p><b>lōʾ-tĕʾunneh ʾēlêkhā rāʿāh</b> — <i>no evil will happen to you</i>. <i>ʾĀnan</i> (pual: to befall, happen to — used of bad things that meet you). <b>wĕnega lōʾ-yiqrab bĕʾāhŏlekhā</b> — <i>and no plague will come close to your tent</i>. <i>Negaʿ</i> (blow, plague, affliction) + <i>bĕʾāhŏlekhā</i> (your tent — the domestic, dwelling space). The protection extends from the person to the household. This is the protective covenant promise that undergirds the psalm — not a guarantee of absolute physical immunity but of the covenant shelter of divine care.</p>",
    "11": "<p><b>kî malʾākhāyw yĕṣawweh-lākh lishmorĕkhā bĕkhol-dĕrākhêkhā</b> — <i>for he will command his angels concerning you to guard you in all your ways</i>. The divine commissioning of angels for personal protection — <i>ṣāwāh</i> (to command) applied to the angels' assignment. <i>Bĕkhol-dĕrākhêkhā</i> (in all your ways — not just the religious ways but every path). This verse and v12 are quoted by the adversary in Matt 4:6 / Luke 4:10-11 in the temple-pinnacle temptation — not a misquotation but a misapplication: the text promises protection in the normal paths of life, not in a spectacular act of self-endangerment to force God's hand.</p>",
    "12": "<p><b>ʿal-kappayim yiśśāʾûnekhā</b> — <i>they will carry you on their hands</i>. <i>Kappayim</i> (palms of the hands) — the angels bearing the protected person in their open hands, preventing a fall. <b>pen-tiggōph bāʾeben raglekhā</b> — <i>lest your foot strike against a stone</i>. <i>Nāgaph</i> (to strike, stumble) — the protection from even ordinary stumbling. The extreme care described (angels carrying in their palms, preventing foot from touching a stone) expresses the totality of divine protection — it is this total protection that makes the adversary's misuse in Matt 4 a distortion: the promise covers the ordinary paths of life, not a theatric leap from the temple parapet.</p>",
    "13": "<p><b>ʿal-shaḥal wāphethen tidrokh</b> — <i>you will tread on the lion and the cobra</i>. <i>Shaḥal</i> (young lion — the vigorous prime lion) + <i>pethen</i> (cobra, the Egyptian cobra — the most deadly serpent known to ancient Israelites). <b>tirmos kĕphîr wĕtannîn</b> — <i>you will trample the young lion and the great serpent</i>. <i>Kĕphîr</i> (young lion) + <i>tannîn</i> (sea dragon, great serpent — the chaos monster of Gen 1:21; Ps 74:13; Isa 51:9). The treading on dangerous creatures echoes Gen 3:15 (enmity between the seed and the serpent) and is echoed in Luke 10:19 (Jesus granting authority to tread on serpents). The dangerous creatures represent all powers hostile to the protected one.</p>",
    "14": "<p><b>kî bî ḥāshaq waʾăpalleṭēhû</b> — <i>'Because he clings to me in love,' declares the LORD, 'I will rescue him'</i>. The divine first-person speech (vv14-16) — God speaking directly about the trusting person. <i>Ḥāshaq</i> (to cling to, be attached to in love — the devoted attachment that cannot be separated; used of Israel's election, Deut 7:7). <b>ʾăśaggĕbēhû kî yādaʿ shĕmî</b> — <i>I will set him beyond reach, because he truly knows who I am</i>. <i>Śāgab</i> (piel: to set high and out of reach) — exaltation as protection. <i>Yādaʿ shĕmî</i> (he knows my name) — intimate personal knowledge of the divine name and character as the basis for the divine response.</p>",
    "15": "<p><b>yiqrāʾēnî wĕʾeʿĕnēhû</b> — <i>when he calls on me I will answer</i>. The covenant prayer-promise: calling and answering as the basic transaction of relationship. <b>ʿimmô-ʾānôkhî bĕṣārāh</b> — <i>I will be with him in his trouble</i>. <i>ʿImmô ʾānôkhî</i> (I myself am with him) — the divine presence with the sufferer in the midst of the trouble (<i>ṣārāh</i>: distress, straits), not removal from it. <b>ʾăḥallĕṣēhû waʾăkhabbĕdēhû</b> — <i>I will rescue him and give him honor</i>. <i>Ḥālaṣ</i> (hiphil: to rescue, deliver — to pull free from danger) + <i>kābēd</i> (piel: to honor, give weight to — the bestowal of the divine honor on the one who clings to God).</p>",
    "16": "<p><b>ʾōrekh yāmîm ʾaśbîʿēhû</b> — <i>I will give him a long life</i>. <i>ʾōrekh yāmîm</i> (length of days — the covenantal long life of Deut 11:9; Prov 3:16) — the divine gift of life's full measure. <b>wĕʾarʾēhû bishûʿātî</b> — <i>and let him see my saving power</i>. <i>Rāʾāh bishuāʿāh</i> (to see the salvation) — the final covenant gift: witnessing the divine salvation in its fullness. The psalm closes with God's own declaration — the divine voice directly promising what the entire psalm has described from the human side.</p>"
  },
  "92": {
    "1": "<p><b>mizmôr shîr lĕyôm hashshabbāt</b> — <i>A Psalm. A Song for the Sabbath day</i>. The only psalm with this specific Sabbath title — its placement in the Psalter and its content (the divine work celebrated, the wicked's apparent flourishing addressed, the righteous ultimately vindicated) fit the Sabbath's theological scope: the day that celebrates the goodness of completed creation and anticipates its eschatological fulfillment. <b>ṭôb lĕhôdôt laYHWH</b> — <i>it is good to give thanks to the LORD</i>. <i>Ṭôb</i> (good) — the creation-goodness word of Gen 1, applied to the act of thanksgiving. <b>ûlĕzammēr lĕshimĕkhā ʿelyôn</b> — <i>to sing praises to your name, O Most High</i>. <i>Zāmar</i> (to make music, to sing praise — often with instruments) to <i>ʿelyôn</i> (the Most High — the God who governs all).</p>",
    "2": "<p><b>lĕhaggîd baqqōqer ḥasdekā</b> — <i>to declare your steadfast love each morning</i>. <i>Ḥesed</i> announced in the morning — the morning as the time of covenant renewal and the experience of fresh grace (cf. Lam 3:22-23). <b>wĕʾĕmûnātĕkhā ballêlôt</b> — <i>and your faithfulness through every night</i>. The pairing: ḥesed for the morning (the active covenant love) + ʾĕmûnāh for the night (the reliability that sustains through darkness). The full day covered by the two divine attributes — the Sabbath as the day when both are proclaimed.</p>",
    "3": "<p><b>ʿălê-ʿāśôr wăʿălê-nābel</b> — <i>to the music of the ten-stringed instrument and the lute</i>. <i>ʿĀśôr</i> (ten-stringed instrument) + <i>nābel</i> (lute, harp — a large, pear-shaped stringed instrument). <b>ʿălê higgāyôn bĕkhinnôr</b> — <i>and the rippling of the lyre</i>. <i>Higgāyôn</i> (a murmuring, rippling sound — possibly a specific type of music, or the low melodious sound of the lyre; the word also appears in Ps 9:16 as a musical direction). The three instruments create a full ensemble of praise — string instruments covering different registers of sound.</p>",
    "4": "<p><b>kî śimmahătanî YHWH bĕphāʿŏlekā</b> — <i>you have made me glad, LORD, by what you have done</i>. The personal testimony (<i>śimmahătanî</i>: you made me glad — the same verb as the petition of Ps 90:14-15). <i>Bĕphāʿŏlekā</i> (by your deed/work) — the divine action as the source of human gladness. <b>bĕmaʿăśēh yādêkhā ʾărannēn</b> — <i>I sing for joy over all that your hands have made</i>. <i>Rānan</i> (to shout for joy — the loud, ringing cry of joy) at the divine handiwork. The Sabbath context: the work of YHWH's hands that calls forth joy is the completed creation rested from on the seventh day.</p>",
    "5": "<p><b>māh-gādĕlû maʿăśêkhā YHWH</b> — <i>how great are your works, LORD!</i> The exclamation of wonder at the divine deeds — <i>māh-gādĕlû</i> (how great! — the exclamatory māh). <b>mĕʾōd ʿāmĕqû maḥshĕbōtekhā</b> — <i>how utterly deep are your thoughts!</i> <i>ʿĀmaq</i> (to be deep — the depth that cannot be fathomed from below). <i>Maḥshābāh</i> (thought, plan, design — the divine cognitive activity that produces the observed works). The works are visible; the thoughts behind them are deep beyond human comprehension (cf. Isa 55:8-9; Rom 11:33).</p>",
    "6": "<p><b>ʾîsh-baʿar lōʾ yēdāʿ ûkhĕsîl lōʾ-yābîn ʾet-zōʾt</b> — <i>a senseless person cannot grasp it, and a fool does not understand this</i>. <i>Baʿar</i> (brutish, stupid — one who behaves like an animal, without reason; cf. Ps 73:22). <i>Kĕsîl</i> (fool — the morally/intellectually deficient person who rejects wisdom). The two types of incomprehension: the brutish senselessness that cannot see, and the deliberate foolishness that refuses to understand. What they cannot grasp is elaborated in v7 — the mystery of the wicked's apparent success.</p>",
    "7": "<p><b>biphroaḥ rĕshāʿîm kĕmô ʿēśeb</b> — <i>the wicked may spring up like grass</i>. <i>Pāraḥ</i> (to blossom, spring up — the growth verb applied to the wicked as to grass). The reversal of the righteous-as-tree image (vv12-14): the wicked flourish like grass — quickly and visibly. <b>wayyāṣîṣû kol-pōʿălê ʾāwen</b> — <i>and every evildoer may flourish</i>. <i>Yāṣîṣ</i> (to blossom brightly — cf. Ps 90:6 where grass blossoms in the morning). <b>lĕhishshāmĕdām ʿădê-ʿad</b> — <i>but they are headed for eternal ruin</i>. <i>ʿAdê-ʿad</i> (forever, into the furthest future) — the flourishing is temporary, the destruction permanent. The temporal contrast: quick grass-flourishing vs. forever-destruction.</p>",
    "8": "<p><b>wĕʾattāh mārôm lĕʿôlām YHWH</b> — <i>while you, LORD, are exalted on high forever</i>. <i>Mārôm</i> (on high — the elevated place of divine reign) + <i>lĕʿôlām</i> (forever). The contrast with the grass of v7: the wicked flourish briefly and perish eternally; YHWH is exalted eternally. The spatial height (<i>mārôm</i>) of divine governance is the frame within which the apparent flourishing of the wicked is correctly evaluated.</p>",
    "9": "<p><b>kî hinnēh ʾōyĕbêkhā YHWH</b> — <i>yes, your enemies, LORD</i>. The <i>kî-hinnēh</i> (for behold) draws attention dramatically to what follows. <b>kî-hinnēh ʾōyĕbêkhā yōʾbēdû</b> — <i>your enemies will certainly perish</i>. <i>ʾĀbad</i> (to perish, be destroyed) — the enemies of YHWH will perish. <b>yitpārĕdû kol-pōʿălê ʾāwen</b> — <i>all who do evil will be scattered</i>. <i>Pārad</i> (niphal: to be scattered, separated) — the dissolution of the apparently cohesive group of evildoers. The repetition of <i>kî hinnēh</i> twice in v9 gives a rhythmic emphasis to the certainty of the outcome.</p>",
    "10": "<p><b>wattārēm kirʾêm qarnî</b> — <i>but you have raised my strength like the horn of a wild ox</i>. <i>Rĕʾēm</i> (the wild ox — the aurochs, <i>Bos primigenius</i>, the immense untameable wild cattle of the ancient Near East; cf. Num 23:22; Deut 33:17; Job 39:9-12). The horn of the wild ox as the image of natural, unconstrained power — not the trained strength of a domestic ox but the raw power of the wild. <b>ballōtî bĕshemen raʿănān</b> — <i>I have been anointed with fresh oil</i>. <i>Raʿănān</i> (fresh, green, lush — the quality of newly pressed oil still full of vitality). The anointing with fresh oil may be literal (festive anointing of Ps 23:5) or metaphorical for divine blessing and refreshment.</p>",
    "11": "<p><b>wattabbēṭ ʿênî bĕshûrāy</b> — <i>my eyes have seen the downfall of my enemies</i>. <i>Shûr</i> (those who watch/lurk against me — from shārar: to be hostile, to watch with hostile intent). The eye-witness to the enemies' downfall — the watching-of-destruction echoed from Ps 91:8. <b>baqāmîm ʿālay mĕrēʿîm tishmaʿnāh ʾoznāy</b> — <i>my ears have heard the ruin of those who rose against me</i>. The double sensory testimony: eyes see and ears hear the fate of those who rose against (<i>qûm ʿālay</i>) the Psalmist.</p>",
    "12": "<p><b>ṣaddîq kattāmār yiphrāḥ</b> — <i>the righteous person flourishes like the palm tree</i>. <i>Tāmār</i> (date palm — Phoenix dactylifera, the tall, stately palm whose fruit comes from near its crown, living for centuries; producing fruit into old age). The contrast with the wicked's grass-flourishing (v7): the wicked are like grass (quick, ephemeral), the righteous are like palm trees (tall, perennial, productive into old age). <b>kĕʾerez ballĕbānôn yiśgeh</b> — <i>and grows tall like a cedar of Lebanon</i>. <i>ʾErez ballĕbānôn</i> (cedar of Lebanon — the great mountain cedar, symbol of grandeur and permanence). Two trees representing the two most majestic forms of botanical life known to ancient Israel.</p>",
    "13": "<p><b>shĕtûlîm bĕbêt YHWH</b> — <i>planted in the house of the LORD</i>. <i>Shātûl</i> (transplanted, planted — the passive participle: these are not self-seeded wild growths but deliberately planted trees). <b>bĕḥaṣrôt ʾĕlōhênû yaphriʾû</b> — <i>they will flourish in the courts of our God</i>. The planting location: <i>bêt YHWH</i> (house of YHWH) + <i>ḥaṣrôt ʾĕlōhênû</i> (courts of our God). The righteous flourish precisely because they are planted in proximity to God — the source of their life. The temple courts as the garden where God's people thrive.</p>",
    "14": "<p><b>ʿôd yĕnûbûn bĕśêbāh</b> — <i>in old age they still produce fruit</i>. <i>Nûb</i> (to bring forth fruit — the productive bearing of the tree). <i>ʾbĕśêbāh</i> (in grey-haired old age — the silvery hair of the aged). The contrast with human transience in Ps 90: here the righteous remain fruitful in old age, like the palm whose fruit-bearing continues for decades. <b>dĕshēnîm wĕraʿănannîm yihyû</b> — <i>they remain vigorous and full of life</i>. <i>Dāshēn</i> (fat, well-nourished, flourishing — the full health that comes from proper nourishment) + <i>raʿănān</i> (fresh, green — the word for the fresh oil of v10). Vitality maintained through old age as the covenant outcome.</p>",
    "15": "<p><b>lĕhaggîd kî-yāshār YHWH</b> — <i>to declare that the LORD is just</i>. The final function of the righteous: they bear witness (<i>higgîd</i>: to declare, make known) to the divine justice. Their own flourishing is itself the testimony. <b>ṣûrî wĕlōʾ-ʿawlātāh bô</b> — <i>my rock, and there is nothing wrong in him</i>. <i>Ṣûr</i> (rock — the bedrock on which the trusting person stands, cf. Deut 32:4). <i>ʿAwlāh</i> (injustice, wrong, perversity) — its negation: <i>lōʾ-ʿawlātāh bô</i> (no injustice in him). The closing confession declares the full vindication of YHWH's justice despite the apparent flourishing of the wicked in v7 — the Sabbath psalm ends with the divine righteousness as the bedrock reality.</p>"
  },
  "93": {
    "1": "<p><b>YHWH mālākh gēʾût lābēsh</b> — <i>the LORD reigns! He is clothed with majesty</i>. <i>YHWH mālākh</i> (the LORD reigns/has become king) — the enthronement proclamation formula that opens the cluster of enthronement psalms (93, 95-99). Whether <i>mālākh</i> is timeless-present (always reigns) or a punctual past (has just become king in a liturgical ceremony) has been much debated; the proclamation asserts both eternal sovereignty and its immediate recognition. <i>Gēʾût lābēsh</i> (clothed in majesty — from gāʾāh: to rise, be exalted; the swelling, surging of divine glory). <b>lābēsh YHWH ʿōz hitʾazzār</b> — <i>the LORD is dressed in strength and has girded himself</i>. <i>Hitʾazzār</i> (hitpael of ʿāzar: to gird oneself — the warrior's preparation). <b>ʾap-tikkôn tēbēl bal-timmôṭ</b> — <i>the world is firmly established — it cannot be shaken</i>. <i>Tikkôn</i> (niphal of kûn: to be established, fixed) — creation's stability as the consequence of divine sovereignty.</p>",
    "2": "<p><b>nākhôn kissĕʾăkhā mēʾāz</b> — <i>your throne has been established from ancient times</i>. <i>Nākhôn</i> (established, fixed — the same root as <i>tikkôn</i> in v1) — the divine throne's stability mirrors the world's stability: both fixed by the same sovereign. <i>Mēʾāz</i> (from of old, from long ago — the deep past; cf. Mic 5:2's <i>mîqedem mîmê ʿôlām</i>). <b>mēʿôlām ʾāttāh</b> — <i>you yourself are from everlasting</i>. <i>Mēʿôlām</i> (from eternity, from the indefinitely ancient past) — YHWH's own existence predates the throne he occupies and the world it governs; the most compressed statement of divine eternity in the psalm.</p>",
    "3": "<p><b>nāśĕʾû nĕhārôt YHWH nāśĕʾû nĕhārôt qôlām</b> — <i>the great waters have lifted up their voice, LORD; the rushing floods have lifted up their voice</i>. The triple repetition of <i>nāśĕʾû nĕhārôt</i> (the rivers/floods have lifted up) mimics the rising surging of waters — the anaphora performs the flood's insistent swelling. <b>yiśśĕʾû nĕhārôt dākyām</b> — <i>and their crashing waves</i>. <i>Dākî</i> (crashing, pounding waves — from dākhāh: to crush, pound). The chaos-waters making themselves heard — the cosmic challenge to divine sovereignty that v4 answers.</p>",
    "4": "<p><b>miqqōlôt mayim rabbîm</b> — <i>mightier than the roar of many waters</i>. <i>Mayim rabbîm</i> (many waters — the chaotic primordial flood; cf. Rev 17:1 where many waters are the nations) — the most powerful force in the ancient Near Eastern cosmological imagination. <b>ʾaddîrîm mishbĕrê-yām</b> — <i>mightier than the waves of the sea</i>. <i>Mishbār</i> (breaker, crashing wave) of the sea — the sea in its most violent aspect. <b>ʾaddîr bammarôm YHWH</b> — <i>the LORD on high is mighty</i>. <i>ʾAddîr</i> (mighty, majestic — the great-power word) placed both at the beginning (waters mighty) and the end (LORD mighty) — the seas' power compared to YHWH's. YHWH's power in the high place (<i>bammarôm</i>) exceeds both. The cosmic battle is over before it begins.</p>",
    "5": "<p><b>ʿēdōtekhā neʾĕmnû mĕʾōd</b> — <i>your decrees are completely trustworthy</i>. <i>ʿĒdâh</i> (testimonies, decrees — the divine statutes as witness to YHWH's character; cf. Ps 19:7). <i>Neʾĕmnû</i> (niphal of ʾāman: they are reliable, trustworthy — the root of <i>ʾāmēn</i>). The moral order (<i>ʿēdôt</i>: the divine testimony-law) matches the physical order (the world established, v1) — both secured by the same divine sovereignty. <b>lĕbêtekhā naʾăwāh-qōdesh YHWH lĕʾōrekh yāmîm</b> — <i>holiness befits your house, LORD, forevermore</i>. <i>Nāʾāh</i> (to be fitting, to become, to adorn) — holiness (<i>qōdesh</i>) adorns/befits the divine house as <i>gēʾût</i> adorns YHWH in v1. The psalm closes with the moral attribute (holiness) answering the cosmic attribute (majesty): the King who defeats the chaos-waters is also the Holy One whose house is adorned with holiness.</p>"
  },
  "94": {
    "1": "<p><b>ʾēl-nĕqāmôt YHWH ʾēl nĕqāmôt hôphîaʿ</b> — <i>O LORD, God of vengeance — God of justice, arise and shine forth!</i> <i>Nĕqāmôt</i> (plural of nĕqāmāh: retribution, vengeance — from nāqam: to avenge, execute retributive justice). The plural may intensify (great retribution) or refer to multiple acts of just retribution. The term is not personal revenge but the legal execution of justice — YHWH as the impartial judge who balances the scales. <i>Hôphîaʿ</i> (hiphil imperative of yāphaʿ: to shine forth, appear in splendor — the request for the divine judicial appearance to become visible).</p>",
    "2": "<p><b>hinnāśēʾ shōpheṭ hāʾāreṣ</b> — <i>rise up, Judge of the earth</i>. <i>Nāśāʾ</i> (niphal imperative: rise up — the judge taking his seat of authority). <i>Shōphēṭ hāʾāreṣ</i> (Judge of the earth) — the title Abraham used in his intercession for Sodom (Gen 18:25: <i>hashōphēṭ kol-hāʾāreṣ lōʾ yaʿăśeh mishpāṭ</i>). <b>hāshēb gĕmûl ʿal-gēʾîm</b> — <i>pay back to the proud what they deserve</i>. <i>Gĕmûl</i> (recompense, what is owed — the return that matches the deed) on the <i>gēʾîm</i> (proud, arrogant ones — from gāʾāh: to swell, rise high).</p>",
    "3": "<p><b>ʿad-māthay rĕshāʿîm YHWH ʿad-māthay rĕshāʿîm yaʿălōzû</b> — <i>how long, LORD, will the wicked — how long will the wicked rejoice in triumph?</i> The doubled <i>ʿad-māthay</i> (how long? how long?) — the urgency of the theodicy question expressed through repetition. <i>ʿĀlaz</i> (to exult, rejoice triumphantly — often the celebration of an unexpected victory). The wicked's exulting is the affront: they should be silent before the divine judge, but instead they celebrate.</p>",
    "4": "<p><b>yabbîʿû yĕdabbĕrû ʿātāq</b> — <i>they spew proud words without end</i>. <i>Nābaʿ</i> (hiphil: to pour out, gush forth — the uncontrolled outpouring of speech). <i>ʿātāq</i> (proud, arrogant things — words of presumptuous arrogance, the speech of those who think they are beyond accountability). <b>yitʾammĕrû kol-pōʿălê ʾāwen</b> — <i>all who do evil brag without restraint</i>. <i>ʾĀmar</i> (hitpael: to show oneself great, boast) — the evil-doers' self-display as the antithesis of fearing God.</p>",
    "5": "<p><b>ʿammĕkhā YHWH yĕdakĕʾû</b> — <i>they crush your people, LORD</i>. <i>Dākhāʾ</i> (piel: to crush, pound — the same root as Ps 90:3's <i>dakkāʾ</i>: crushed dust). The victims identified: <i>ʿammĕkhā</i> (your people) — which means the oppression is not only against the weak but against YHWH himself. <b>wĕnaḥălātĕkhā yĕʿannû</b> — <i>and oppress those who belong to you</i>. <i>Naḥălāh</i> (inheritance, property — Israel as YHWH's own possession). To oppress God's <i>naḥălāh</i> is to violate divine property — the crime is against the owner of the people, not only against the people.</p>",
    "6": "<p><b>ʾalmānāh wĕgēr yahărōgû</b> — <i>they murder the widow and the foreigner</i>. <i>ʾAlmānāh</i> (widow) + <i>gēr</i> (resident alien, foreigner — the protected classes of Israelite law: Exod 22:21-24; Deut 24:17-22; Lev 19:9-10). These are precisely the ones the Mosaic law most explicitly protects. <b>wîtômîm yĕrāṣĕḥû</b> — <i>and kill the fatherless</i>. <i>Yātôm</i> (orphan) — the third member of the classic triad (widow, orphan, stranger) that appears throughout the prophets as the test of social justice (Isa 1:17; Jer 7:6; Zech 7:10; Mal 3:5).</p>",
    "7": "<p><b>wayyōʾmĕrû lōʾ yirʾeh-YAH</b> — <i>and they say, 'The LORD never sees it'</i>. <i>Yirʾeh-YAH</i> (the LORD does not see) — the theological premise of the oppressor: practical atheism, the denial of divine observation. <b>wĕlōʾ-yābîn ʾĕlōhê yaʿăqōb</b> — <i>the God of Jacob pays no attention</i>. <i>Bîn</i> (to understand, perceive — judicial discernment). The <i>ʾĕlōhê yaʿăqōb</i> (God of Jacob) — the covenant God of the patriarchs, who should above all perceive the suffering of his people, is claimed by the oppressor not to notice. The psalmist's counter-argument follows in vv9-11.</p>",
    "8": "<p><b>bînû bōʿărîm bāʿām</b> — <i>grasp this, you most senseless among the people</i>. <i>Bîn</i> (imperative: understand, discern) directed at the <i>bōʿărîm</i> (the brutish/senseless ones — cf. Ps 92:6: <i>ʾîsh-baʿar</i>). <b>ûkhĕsîlîm māthay taskîlû</b> — <i>fools, when will you become wise?</i> <i>Kĕsîlîm</i> (fools — the morally obtuse). The rhetorical address directly to the oppressors, inviting them to use the faculty of reason they are demonstrating they lack.</p>",
    "9": "<p><b>hănōṭaʿ ʾōzen hălōʾ yishmaʿ</b> — <i>the one who made the ear — does he not hear?</i> The qal wahomer (from minor to major) argument: the ear's Creator must be able to do what the ear can do. <i>Nāṭaʿ</i> (to plant, to form — the delicate craftsmanship of forming the ear). If a human craftsman understands the instrument he has crafted, how much more the divine craftsman who created hearing itself. <b>ʾim-yōṣēr ʿayin hălōʾ yabbîṭ</b> — <i>the one who formed the eye — does he not see?</i> The parallel: the eye's Formation (yāṣar: the potter's crafting of the eye's form) implies the ability to see. The argument from creation to Creator's capacities.</p>",
    "10": "<p><b>hăyōsēr gôyim hălōʾ yôkhîaḥ</b> — <i>the one who corrects the nations — will he not call them to account?</i> <i>Yāsar</i> (to discipline, correct, instruct — the instructive discipline that brings nations to order). If YHWH disciplines entire nations, how could he fail to call individual oppressors to account? <b>hămĕlammēd ʾādām daʿat</b> — <i>the one who teaches all people</i>. <i>Limmēd</i> (piel: to teach) — the divine pedagogy directed toward all humanity (<i>ʾādām</i>: the collective human being).</p>",
    "11": "<p><b>YHWH yōdēaʿ maḥshĕbôt ʾādām kî-hēmmāh hebel</b> — <i>the LORD knows human beings' thoughts — that they are nothing but vapor</i>. The divine knowledge <i>maḥshĕbôt ʾādām</i> (the thoughts/plans of humanity) — YHWH knows them precisely and has evaluated them: <i>hēmmāh hebel</i> (they are vapor, emptiness — the Qoheleth word for the insubstantial transience of all human projects). This verse is quoted by Paul in 1 Cor 3:20 (<i>kurios ginōskei tous dialogismous tōn sophōn</i>: the Lord knows the reasonings of the wise, that they are futile) — applied to the futility of human wisdom compared to divine wisdom. The oppressors' plans are known to God and evaluated as <i>hebel</i>.</p>",
    "12": "<p><b>ʾashrê haggeber ʾăsher-tĕyassĕrennû YAH</b> — <i>blessed is the man whom you discipline, LORD</i>. <i>ʾAshrê</i> (blessed — the beatitude formula; cf. Ps 1:1) + <i>yāsar</i> (to discipline, instruct): blessing comes through discipline. <b>ûmitôrātekhā tĕlammĕdennû</b> — <i>and instruct from your teaching</i>. <i>Tôrāh</i> (teaching, instruction — the Torah as the divine curriculum through which YHWH instructs his people). The disciplined person is blessed not despite the hardship but through it — the instruction given through suffering.</p>",
    "13": "<p><b>lĕhashqîṭ lô mîmê rāʿ</b> — <i>giving him rest in days of trouble</i>. <i>Hashqîṭ</i> (hiphil of shāqaṭ: to give rest, to make quiet — the resting-from-trouble that the disciplined person receives). <b>ʿad yikkāreh lārāshāʿ shāḥat</b> — <i>until a pit is dug for the wicked</i>. The temporary nature of the trouble: the disciplined righteous person rests while the wicked's pit is being prepared. <i>Shāḥat</i> (pit — both literal and metaphorical: the grave/destruction that awaits).</p>",
    "14": "<p><b>kî lōʾ-yiṭōsh YHWH ʿammô</b> — <i>the LORD will not abandon his people</b>. <i>Nāṭash</i> (to abandon, forsake, cast off — the action of leaving without looking back). <b>wĕnaḥălātô lōʾ yaʿăzōb</b> — <i>or desert his inheritance</i>. <i>ʿĀzab</i> (to abandon, leave) — the two verbs together (<i>nāṭash</i> + <i>ʿāzab</i>) reinforce the covenantal commitment: YHWH will not leave his <i>naḥălāh</i> (cf. Deut 4:31; 31:6; Josh 1:5). The confidence grounding the lament of vv3-11 and the petition of v1-2.</p>",
    "15": "<p><b>kî-ʿad-ṣedeq yāshûb mishpāṭ</b> — <i>for justice will return to the righteous</i>. <i>Shûb</i> (to return — justice reverting to its proper place with the righteous after its apparent absence). <b>wĕʾaḥărāyw kol-yishĕrê-lēb</b> — <i>and all who are upright in heart will pursue it</i>. <i>Yāshār-lēb</i> (upright of heart — the opposite of the hardened heart of v8; the person whose inner compass is aligned correctly). The return of justice creates a rally of the upright — they pursue what has returned.</p>",
    "16": "<p><b>mî-yāqûm lî ʿim-mĕrēʿîm</b> — <i>who will stand up for me against the wicked?</i> The personal lament-question: who will rise as an advocate against the <i>mĕrēʿîm</i> (those who do evil — piel participle of rāʿaʿ: to do harm)? <b>mî-yityaṣṣēb lî ʿim-pōʿălê ʾāwen</b> — <i>who will take my side against evildoers?</i> <i>Yāṣab</i> (hitpael: to station oneself, take a position as an advocate or champion). The implied answer: only YHWH, as vv17-19 confirm.</p>",
    "17": "<p><b>lûlê YHWH ʿezrātāh lî</b> — <i>if the LORD had not been my help</i>. <i>Lûlê</i> (if not — the conditional of disaster: what would have happened without divine intervention). <b>kimaʿaṭ shākhĕnāh dûmāh nafshî</b> — <i>I would very soon have lain in the silence of death</i>. <i>Dûmāh</i> (silence — the silence of death; cf. Ps 115:17: <i>lōʾ hammētîm yĕhallĕlû-YAH wĕlōʾ kol-yōrĕdê dûmāh</i>: not the dead praise the LORD, not those going down to silence). The narrow escape: <i>kimaʿaṭ</i> (almost, nearly) — the Psalmist was almost in the silence of death but for YHWH's intervention.</p>",
    "18": "<p><b>ʾim-ʾāmartî māṭāh raglî</b> — <i>when I felt my foot giving way</i>. <i>Māṭāh</i> (to be inclined, to slip — the foot losing its footing). The moment of crisis described with simplicity: the foot slipping is enough to indicate the totality of the threat. <b>ḥasdĕkhā YHWH yisʿādēnî</b> — <i>your steadfast love, LORD, held me steady</i>. <i>Sāʿad</i> (to support, uphold, prop up — the prop placed under the slipping foot). The divine ḥesed as the stabilizing force under the failing foot — the covenant love as the practical ground underfoot.</p>",
    "19": "<p><b>bĕrōb śarʿappay bĕqirbî</b> — <i>when anxious thoughts multiply inside me</i>. <i>Śarʿappîm</i> (anxious thoughts, disquieting thoughts — from śāraph: to divide, split; the inner splitting of anxiety; hapax in this form). The internal experience: the multiplication of worrying thoughts within (<i>bĕqirbî</i>: inside me). <b>tanhûmekhā yĕshaʿăshĕʿû nafshî</b> — <i>your comfort brings delight to my soul</i>. <i>Tanḥûm</i> (consolation, comfort — from nāḥam: to comfort, console). <i>Shaʿashuaʿ</i> (to delight, to bring exquisite pleasure — a rare intensive form: the divine comfort not merely quieting the anxiety but producing delight in the soul).</p>",
    "20": "<p><b>hăyĕḥābrĕkhā kissēʾ hawwôt</b> — <i>can a corrupt throne have any fellowship with you?</i> <i>Ḥābar</i> (to be associated with, have fellowship/partnership with) — can the throne of <i>hawwôt</i> (ruin, destruction, malicious plans — the corrupt power that enacts harm) have any association with YHWH? The implied answer is no — YHWH cannot be in covenant with or complicit in corrupt governance. <b>yōṣēr ʿāmāl ʿălê-ḥōq</b> — <i>one that enacts harm through its own laws</i>. <i>ʿĀmāl</i> (trouble, injustice) enacted <i>ʿălê-ḥōq</i> (by/through statute, through official legislation) — the oppression that uses legal forms to perpetrate injustice is what the psalm specifically addresses: structural evil embedded in law.</p>",
    "21": "<p><b>yāgôddû ʿal-nefesh ṣaddîq</b> — <i>they join forces against the lives of the righteous</i>. <i>Gādad</i> (hitpolel: to band together, mass against — the organized assault of a group). <b>wĕdām nāqî yarshîʾû</b> — <i>and condemn the innocent to death</i>. <i>Dām nāqî</i> (innocent blood — the blood of the guiltless) condemned (<i>rāshāʿ</i>: piel: to declare guilty, to condemn as guilty — the judicial condemnation of the blameless). The corruption of the legal system reaches its apex: innocent blood condemned through legal process.</p>",
    "22": "<p><b>wayhî YHWH lî lĕmiśgāb</b> — <i>but the LORD is my strong fortress</i>. <i>Miśgāb</i> (high fortress, elevated refuge — from śāgab: to be high, inaccessible; cf. Ps 91:14 where the trusting person is placed beyond reach). The turn from complaint to confidence: <b>wĕʾĕlōhay lĕṣûr maḥsî</b> — <i>and my God is the rock where I take shelter</i>. <i>Ṣûr maḥsî</i> (rock of my refuge) — the two bedrock images (fortress + rock) combined as the divine basis of security against the corrupt power of v20-21.</p>",
    "23": "<p><b>wayyāsheb ʿălêhem ʾet-ʾôwnām</b> — <i>he will pay them back for their sin</i>. <i>Shûb ʿāl</i> (hiphil: to bring back upon — the divine recoil of their <i>ʾāwen</i> [iniquity, evil] back onto those who committed it). <b>ûbĕrāʿātām yaṣmîtēm</b> — <i>and destroy them for their evil</i>. <i>Ṣāmat</i> (hiphil: to cut off, silence, destroy completely — used of the wicked's destruction, cf. Ps 18:40; 88:16). <b>yaṣmîtēm YHWH ʾĕlōhênû</b> — <i>the LORD our God will wipe them out</i>. The closing reiteration of the divine name: the God who was invoked in v1 as the God of retributions delivers the retribution at the psalm's close.</p>"
  },
  "95": {
    "1": "<p><b>lĕkhû nĕrannĕnāh laYHWH</b> — <i>come, let us sing joyfully to the LORD</i>. <i>Rānan</i> (to give a ringing shout of joy — the loud, exuberant communal cry that opens worship). The cohortative <i>nĕrannĕnāh</i> (let us shout/sing) is the liturgical call to corporate worship. <b>nārîʿāh lĕṣûr yishʿênû</b> — <i>let us shout aloud to the Rock who saves us!</i> <i>Rûaʿ</i> (hiphil: to shout in triumph/worship — the blast of joy). <i>Ṣûr yishʿênû</i> (Rock of our salvation) — the title from Ps 89:26 where the anointed king calls YHWH <i>ṣûr yĕshûʿātî</i>; here applied to the community's corporate salvation.</p>",
    "2": "<p><b>nĕqaddĕmāh phānāyw bĕtôdāh</b> — <i>let us come before him with thanksgiving</i>. <i>Qādam pānim</i> (to come before the face — to approach the divine presence as a subject approaches a king). <i>Tôdāh</i> (thanksgiving — the specific sacrifice/act of thanksgiving in Israelite worship, from yādāh: to acknowledge, confess, thank). <b>bizkĕmîrôt nārîaʿ lô</b> — <i>and celebrate him with songs of praise</i>. <i>Mĕzimmôt</i> (psalms, songs — the musical compositions of praise offered in the temple). The two modes of approach: thanksgiving and song.</p>",
    "3": "<p><b>kî ʾēl gādôl YHWH ûmelek gādôl ʿal-kol-ʾĕlōhîm</b> — <i>for the LORD is a great God, a great King greater than all other gods</i>. The grounding <i>kî</i> (for/because) gives the reason for worship: YHWH's divine identity. <i>ʾĒl gādôl</i> (great God) + <i>melek gādôl</i> (great King) — the double title acknowledges YHWH's divine nature and sovereign rule simultaneously. <i>ʿAl-kol-ʾĕlōhîm</i> (over all the gods) — the incomparability formula positioning YHWH over all other divine claimants, as in Ps 86:8; 89:6-7.</p>",
    "4": "<p><b>ʾăsher bĕyādô meḥqĕrê-ʾāreṣ</b> — <i>the deepest places of the earth are in his hand</i>. <i>Meḥqār</i> (deep recesses, hidden depths — from ḥāqar: to search out) of the earth — the inaccessible underground depths. <b>wĕtôʿăphôt hārîm lô</b> — <i>and the mountain peaks belong to him</i>. <i>Tôʿāphôt</i> (heights, peaks — the extreme high points) of the mountains. The vertical sovereignty: from the deepest underground (<i>meḥqĕrê-ʾāreṣ</i>) to the highest peaks (<i>tôʿăphôt hārîm</i>) — the full vertical range of the created order belongs to YHWH.</p>",
    "5": "<p><b>ʾăsher-lô hayyām wĕhûʾ ʿāśāhû</b> — <i>the sea is his — he made it</i>. Ownership grounded in creation: <i>lô</i> (his) because <i>ʿāśāhû</i> (he made it). The sea that the chaos-waters of Ps 93:3-4 threatened to overwhelm YHWH's rule belongs to him as its maker — possession precedes and defeats the chaos-threat. <b>wĕyabbāshet yādāyw yāṣārû</b> — <i>his own hands shaped the dry land</i>. <i>Yāṣar</i> (to form, shape — the potter's forming; cf. Gen 2:7 where YHWH forms the man from dust). The dry land formed by YHWH's hands — the same hands that hold the depths (v4). All the earth is his handiwork.</p>",
    "6": "<p><b>bōʾû nishṭaḥăweh wĕnikhrāʿāh</b> — <i>come, let us bow down and worship</i>. The second call to worship (<i>bōʾû</i>: come — cf. v1's <i>lĕkhû</i>: come), now shifting from joyful shouting (vv1-2) to reverent prostration (<i>shāḥāh</i>: to bow low, prostrate oneself in worship) and kneeling (<i>kāraʿ</i>: to kneel). <b>nibrĕkhāh liphnê-YHWH ʿōśênû</b> — <i>let us kneel before the LORD who made us</i>. <i>ʿĒśânû</i> (who made us — from ʿāśāh: the same verb as v5 where YHWH made the sea). The congregation as YHWH's handiwork alongside the sea and dry land.</p>",
    "7": "<p><b>kî hûʾ ʾĕlōhênû waʾănaḥnû ʿam marʿîtô wĕṣōʾn yādô</b> — <i>for he is our God, and we are the people of his pasture, the flock he tends</i>. The covenant identity: <i>ʾĕlōhênû</i> (our God) + <i>ʿammô</i> (his people) in the classical covenant formula. <i>Ṣōʾn yādô</i> (the flock of his hand) — the sheep held in God's hand, cared for with his own hand (cf. Ezek 34:31's good shepherd promise). <b>hayyôm ʾim-bĕqōlô tishmaʿû</b> — <i>today — if only you would hear his voice</i>. <i>Hayyôm</i> (today — the urgent, unrepeatable present moment that the divine voice occupies). The psalm pivots abruptly from worship-invitation to covenant-warning. The <i>ʾim</i> (if) marks the conditional threshold.</p>",
    "8": "<p><b>ʾal-taqshû lĕbabĕkhem kimrîbāh</b> — <i>do not harden your hearts, as at Meribah</i>. <i>Qāshāh</i> (hiphil: to make hard, to harden — the deliberate stiffening of the heart against the divine voice). <i>Mĕrîbāh</i> (Meribah — the place of quarreling, from rîb: to contend; Exod 17:7; Num 20:13 where the people contended with God over water). <b>kĕyôm massāh bammidebār</b> — <i>as on that day at Massah in the wilderness</i>. <i>Massāh</i> (testing — from nāsāh: to test; Exod 17:7 where the location was named both Massah and Meribah). The wilderness generation as the paradigmatic warning against hardening.</p>",
    "9": "<p><b>ʾăsher nissûnî ʾăbôtêkhem</b> — <i>your ancestors put me to the test</i>. <i>Nāsāh</i> (to test, to prove — the dangerous reversal: the creature testing the Creator). <b>bĕḥānûnî gam-rāʾû phāʿălî</b> — <i>and challenged me, even after seeing all I had done</i>. <i>Bāḥan</i> (to test, examine — a second verb for testing, as if the first were insufficient to express the audacity). The aggravating circumstance: <i>gam-rāʾû phāʿălî</i> (they also saw my works) — the testing happened despite (<i>gam</i>: also, even) the visual evidence of YHWH's miraculous deeds. Testing after seeing is the supreme ingratitude.</p>",
    "10": "<p><b>ʾarbaʿîm shānāh ʾāqûṭ bĕdôr</b> — <i>for forty years I was provoked by that generation</i>. <i>Qûṭ</i> (qal: to loathe, be disgusted with — from a root related to deep revulsion; used here of God's attitude toward the wilderness generation). This is an unusually intense verb for divine reaction — not simply anger but something closer to moral nausea at persistent rebellion. <b>wāʾōmar ʿam tōʿê-lēbāb hēm</b> — <i>and declared, 'This people's heart keeps wandering'</i>. <i>Tāʿāh</i> (to wander, err, stray — as a sheep straying from the path; cf. Ps 119:176). The diagnosis: erring heart (<i>tōʿê-lēbāb</i>) — not occasional failure but a structural disposition to wander. <b>wĕhēm lōʾ-yādĕʿû dĕrākhāy</b> — <i>they have never learned my ways</i>. <i>Yādaʿ</i> (to know — covenant-knowing that includes relational fidelity). They have not internalized the divine ways despite forty years of experience with them.</p>",
    "11": "<p><b>ʾăsher-nishbaʿtî bĕʾappî</b> — <i>so in my anger I swore</i>. <i>Nishbaʿ</i> (niphal of shābaʿ: to swear an oath) <i>bĕʾappî</i> (in my anger — the oath sworn in the moment of divine wrath). <b>ʾim-yĕbōʾûn ʾel-mĕnûḥātî</b> — <i>'They will never enter my rest.'</i> <i>Mĕnûḥāh</i> (rest, resting-place — from nûaḥ: to rest, settle; the concept covers both the physical land-rest of Canaan, Gen 2:2's divine Sabbath rest, and the eschatological rest toward which both point). The <i>ʾim</i> before the oath is the negative oath-formula in Hebrew: <i>ʾim yĕbōʾûn</i> = they shall certainly not enter. The epistle to the Hebrews (Heb 3:7-4:11) reads this verse as describing a rest that remains available — the wilderness generation's exclusion does not exhaust the promise of rest; the <i>hayyôm</i> of v7 is still the door to enter it.</p>"
  }
}

def main():
    data = load_comm('mkt-original', 'psalms')
    merge_comm(data, NEW)
    save_comm('mkt-original', 'psalms', data)
    for ch in ['90', '91', '92', '93', '94', '95']:
        vcount = len(data.get(ch, {}))
        print(f'  Ps {ch}: {vcount} verses')

if __name__ == '__main__':
    main()
